import{_ as a,c as s,o as t,aT as e}from"./chunks/framework.qpm8FIA8.js";const b=JSON.parse('{"title":"Git 创建仓库","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/git/git-create-repository.md","filePath":"frontend/git/git-create-repository.md","lastUpdated":1711621612000}'),i={name:"frontend/git/git-create-repository.md"},p=e(`<h1 id="git-创建仓库" tabindex="-1">Git 创建仓库 <a class="header-anchor" href="#git-创建仓库" aria-label="Permalink to &quot;Git 创建仓库&quot;">​</a></h1><p>本章节我们将为大家介绍如何创建一个 Git 仓库。</p><p>你可以使用一个已经存在的目录作为 Git 仓库。</p><h2 id="git-init" tabindex="-1">git init <a class="header-anchor" href="#git-init" aria-label="Permalink to &quot;git init&quot;">​</a></h2><p>Git 使用 <code>git init</code> 命令来初始化一个 Git 仓库，Git 的很多命令都需要在 Git 的仓库中运行，所以 git init 是使用 Git 的第一个命令。</p><p>在执行完成 <code>git init</code> 命令后，Git 仓库会生成一个 .git 目录，该目录包含了资源的所有元数据，其他的项目目录保持不变。</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><p>使用当前目录作为 Git 仓库，我们只需使它初始化。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>git init</span></span></code></pre></div><p>该命令执行完后会在当前目录生成一个 .git 目录。</p><p>使用我们指定目录作为Git仓库。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>git init newrepo</span></span></code></pre></div><p>初始化后，会在 newrepo 目录下会出现一个名为 .git 的目录，所有 Git 需要的数据和资源都存放在这个目录中。</p><p>如果当前目录下有几个文件想要纳入版本控制，需要先用 git add 命令告诉 Git 开始对这些文件进行跟踪，然后提交：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>$ git add *.c</span></span>
<span class="line"><span>$ git add README</span></span>
<span class="line"><span>$ git commit -m &#39;初始化项目版本&#39;</span></span></code></pre></div><p>以上命令将目录下以 .c 结尾及 README 文件提交到仓库中。</p><h2 id="git-clone" tabindex="-1">git clone <a class="header-anchor" href="#git-clone" aria-label="Permalink to &quot;git clone&quot;">​</a></h2><p>我们使用 <code>git clone</code> 从现有 Git 仓库中拷贝项目（类似 svn checkout）。</p><p>克隆仓库的命令格式为：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>git clone &lt;repo&gt;</span></span></code></pre></div><p>如果我们需要克隆到指定的目录，可以使用以下命令格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>git clone &lt;repo&gt; &lt;directory&gt;</span></span></code></pre></div><p>参数说明：</p><ul><li><p>repo:Git 仓库。</p></li><li><p>directory:本地目录。</p></li></ul><p>比如，要克隆 Ruby 语言的 Git 代码仓库 Grit，可以用下面的命令：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>$ git clone git://github.com/schacon/grit.git</span></span></code></pre></div><p>执行该命令后，会在当前目录下创建一个名为grit的目录，其中包含一个 .git 的目录，用于保存下载下来的所有版本记录。</p><p>如果要自己定义要新建的项目目录名称，可以在上面的命令末尾指定新的名字：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>$ git clone git://github.com/schacon/grit.git mygrit</span></span></code></pre></div><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>git 的设置使用 git config 命令。</p><p>显示当前的 git 配置信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>$ git config --list</span></span>
<span class="line"><span>credential.helper=osxkeychain</span></span>
<span class="line"><span>core.repositoryformatversion=0</span></span>
<span class="line"><span>core.filemode=true</span></span>
<span class="line"><span>core.bare=false</span></span>
<span class="line"><span>core.logallrefupdates=true</span></span>
<span class="line"><span>core.ignorecase=true</span></span>
<span class="line"><span>core.precomposeunicode=true</span></span></code></pre></div><p>编辑 git 配置文件:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>$ git config -e    # 针对当前仓库</span></span></code></pre></div><p>或者：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>$ git config -e --global   # 针对系统上所有仓库</span></span></code></pre></div><p>设置提交代码时的用户信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>$ git config --global user.name &quot;runoob&quot;</span></span>
<span class="line"><span>$ git config --global user.email test@runoob.com</span></span></code></pre></div><p>如果去掉 --global 参数只对当前仓库有效。</p>`,40),n=[p];function o(l,c,d,g,r,h){return t(),s("div",null,n)}const v=a(i,[["render",o]]);export{b as __pageData,v as default};
